parameters.jsCode:
const raw = items[0].json.content[0].text;
const clean = raw.replace(/```json/g,'').replace(/```/g,'').trim();
let seo;
try { seo = JSON.parse(clean); }
catch(e) { throw new Error('Claude parse error: ' + clean.substring(0,200)); }
const script = $('Parse Script').item.json;
return [{ json: {
  title: seo.title || '',
  description: seo.description || '',
  tags: Array.isArray(seo.tags) ? seo.tags : [],
  hook_rewrite: seo.hook_rewrite || script.hook,
  tiktok_caption: seo.tiktok_caption || '',
  hook: script.hook,
  body: script.body,
  cta: script.cta,
  full_script: script.full_script,
  fact: script.fact,
  source: script.source,
  keywords: script.keywords,
  created_at: new Date().toISOString()
}}];

const airtableId = items[0].json.id;
const merged = $('Merge All Data').item.json;
return [{ json: {
  airtable_id: airtableId,
  title: merged.title,
  description: merged.description,
  tags: merged.tags,
  tiktok_caption: merged.tiktok_caption,
  hook: merged.hook_rewrite,
  body: merged.body,
  cta: merged.cta,
  full_script: merged.full_script
}}];

const result = items[0].json;
if (!result.success) {
  throw new Error('Remotion render failed: ' + (result.error || 'Unknown error'));
}
if (!result.video_base64) {
  throw new Error('No video data returned from Remotion server');
}
const data = $('Save Record ID').item.json;
return [{ json: {
  video_base64: result.video_base64,
  filename: result.filename,
  title: data.title,
  description: data.description,
  tags: data.tags,
  tiktok_caption: data.tiktok_caption,
  airtable_id: data.airtable_id
}}];
